    // 1. Create observer nodes
    auto source = std::make_shared<TestTransactionalObserver>(nodeName);
    auto target = std::make_shared<TestTransactionalObserver>("target");

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Set up initial relationship: source observes target
    graph.addObserver(source, target);

    // 4. Notify target and verify relationship works
    target->valueChanged(true);
    if (!source->wasChanged()) {
        return false; // Initial relationship verification failed
    }
    source->reset(); // Reset for next test

    // 5. Attempt transactional update that would create cycle
    // Update source to observe itself (would create cycle if allowed)
    try {
        graph.updateObserversTransactional(source, {source});
    } 
    // 6. Catch cycle exception if thrown
    catch (const std::exception& e) {
        // Cycle exception caught - this is expected behavior
        // 7. Notify target again
        target->valueChanged(true);

        // 8. Verify original relationship is preserved
        if (!source->wasChanged()) {
            return false; // Original relationship not preserved after exception
        }

        // 9. Return success status
        return true; // Transactional update correctly prevented cycle
    }

    // If no exception was thrown, the update succeeded in creating a cycle
    // which violates our test requirements
    return false;
}

