inline LogicalExpressionSnapshot test_logical_expression_builders(bool a, bool b, bool c) {
    // 1. Create reactive boolean variables using reaction::var
    auto var_a = reaction::var(a);
    auto var_b = reaction::var(b);
    auto var_c = reaction::var(c);

    // 2. Build logical AND expression using && operator
    auto and_expr = var_a && var_b;

    // 3. Build logical OR expression using || operator  
    auto or_expr = var_a || var_c;

    // 4. Use expr to create reactive expressions for logical operations
    auto reactive_and = reaction::expr(and_expr);
    auto reactive_or = reaction::expr(or_expr);

    // 5. Use get() to retrieve initial values
    bool initialAnd = reactive_and.get();
    bool initialOr = reactive_or.get();

    // 6. Update variables using value() method to trigger recomputation
    var_a.value(!a);  // Flip the value to trigger change
    var_b.value(!b);  // Flip the value to trigger change  
    var_c.value(!c);  // Flip the value to trigger change

    // 7. Use get() again to retrieve updated values
    bool updatedAnd = reactive_and.get();
    bool updatedOr = reactive_or.get();

    // 8. Return LogicalExpressionSnapshot with all results
    return LogicalExpressionSnapshot{
        .initialAnd = initialAnd,
        .initialOr = initialOr,
        .updatedAnd = updatedAnd,
        .updatedOr = updatedOr
    };
}

}  // namespace test_reaction
```

